// === 5. HTML 생성 ===
const htmlContent = `<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${level} - ${region}</title>
  <style>
    * { margin:0; padding:0; box-sizing:border-box; }
    body {
      min-height:100vh; display:flex; align-items:center; justify-content:center;
      background:linear-gradient(135deg, #f8f0fa 0%, #e8f4f8 100%);
      font-family:'Segoe UI', sans-serif; padding:20px;
    }
    .card {
      max-width:720px; width:100%; border-radius:20px; overflow:hidden;
      background:#fff; box-shadow:0 20px 60px rgba(0,0,0,0.15);
    }
    .image-wrap {
      position:relative; cursor:pointer; overflow:hidden;
    }
    .image-wrap img { width:100%; display:block; transition:transform 0.3s; }
    .image-wrap:hover img { transform:scale(1.02); }
    .play-btn {
      position:absolute; bottom:24px; left:50%; transform:translateX(-50%);
      background:rgba(255,77,77,0.95); color:#fff;
      padding:14px 36px; border-radius:50px; border:none;
      font-size:18px; font-weight:bold; cursor:pointer;
      box-shadow:0 8px 25px rgba(255,77,77,0.4);
      transition:all 0.3s; display:flex; align-items:center; gap:8px;
    }
    .play-btn:hover { background:#e63939; transform:translateX(-50%) scale(1.05); }
    .play-btn.playing { background:#4CAF50; box-shadow:0 8px 25px rgba(76,175,80,0.4); }
    .controls {
      padding:20px 24px; display:flex; align-items:center; justify-content:space-between;
    }
    .badge {
      background:linear-gradient(135deg,#6366f1,#8b5cf6); color:#fff;
      padding:6px 16px; border-radius:20px; font-size:13px; font-weight:600;
    }
    .progress-bar {
      flex:1; margin:0 16px; height:4px; background:#e5e7eb; border-radius:4px;
      overflow:hidden; cursor:pointer;
    }
    .progress-fill {
      height:100%; width:0%; background:linear-gradient(90deg,#6366f1,#ec4899);
      border-radius:4px; transition:width 0.1s;
    }
    .time { font-size:13px; color:#9ca3af; min-width:40px; text-align:right; }
    .error-msg {
      color:#d32f2f; text-align:center; padding:12px; font-size:14px; display:none;
    }
  </style>
</head>
<body>
  <div class="card">
    <div class="image-wrap" onclick="toggleAudio()">
      <img src="${imageUrl}" alt="${level} ${region} Culture Poster">
      <button class="play-btn" id="playBtn">
        <span id="playIcon">▶</span>
        <span id="playText">소리 듣기</span>
      </button>
    </div>
    <div class="controls">
      <span class="badge">${level} · ${region}</span>
      <div class="progress-bar" id="progressBar" onclick="seek(event)">
        <div class="progress-fill" id="progressFill"></div>
      </div>
      <span class="time" id="timeDisplay">0:00</span>
    </div>
    <p class="error-msg" id="errorMsg"></p>
  </div>

  <audio id="myAudio" preload="metadata"></audio>

  <script>
    const audio = document.getElementById("myAudio");
    const playBtn = document.getElementById("playBtn");
    const playIcon = document.getElementById("playIcon");
    const playText = document.getElementById("playText");
    const progressFill = document.getElementById("progressFill");
    const timeDisplay = document.getElementById("timeDisplay");
    const errorMsg = document.getElementById("errorMsg");

    audio.src = "${audioSrc.replace(/"/g, '\\\\"')}";

    audio.addEventListener("timeupdate", () => {
      if (audio.duration) {
        progressFill.style.width = (audio.currentTime / audio.duration * 100) + "%";
        const sec = Math.floor(audio.currentTime);
        timeDisplay.textContent = Math.floor(sec/60) + ":" + String(sec%60).padStart(2,"0");
      }
    });

    audio.addEventListener("error", () => {
      errorMsg.textContent = "오디오 로드 실패: " + (audio.error?.message || "파일을 확인하세요");
      errorMsg.style.display = "block";
    });

    audio.addEventListener("ended", () => {
      playIcon.textContent = "▶";
      playText.textContent = "다시 듣기";
      playBtn.classList.remove("playing");
      progressFill.style.width = "0%";
    });

    function toggleAudio() {
      if (audio.paused) {
        audio.play().then(() => {
          playIcon.textContent = "⏸";
          playText.textContent = "재생 중...";
          playBtn.classList.add("playing");
        }).catch(err => {
          errorMsg.textContent = "재생 오류: " + err.message;
          errorMsg.style.display = "block";
        });
      } else {
        audio.pause();
        playIcon.textContent = "▶";
        playText.textContent = "계속 듣기";
        playBtn.classList.remove("playing");
      }
    }

    function seek(e) {
      e.stopPropagation();
      const bar = document.getElementById("progressBar");
      const ratio = e.offsetX / bar.offsetWidth;
      audio.currentTime = ratio * audio.duration;
    }
  </script>
</body>
</html>`;

